from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
from datetime import datetime
import uuid


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    REVERSED = "reversed"


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class InvalidTransactionError(Exception):
    pass


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    amount: float
    source_account_id: Optional[str]
    destination_account_id: Optional[str]
    timestamp: datetime
    status: TransactionStatus = TransactionStatus.PENDING
    description: str = ""

    def __post_init__(self):
        if self.amount <= 0:
            raise InvalidTransactionError("Transaction amount must be positive.")


@dataclass
class Account:
    account_id: str
    owner_name: str
    balance: float = 0.0
    transaction_history: list = field(default_factory=list)

    def __post_init__(self):
        if self.balance < 0:
            raise ValueError("Initial balance cannot be negative.")


class TransactionProcessor:
    def __init__(self):
        self.accounts: dict[str, Account] = {}
        self.transactions: dict[str, Transaction] = {}

    def create_account(self, owner_name: str, initial_balance: float = 0.0) -> Account:
        """Create a new account with an optional initial balance."""
        account_id = str(uuid.uuid4())[:8]
        account = Account(
            account_id=account_id,
            owner_name=owner_name,
            balance=initial_balance,
        )
        self.accounts[account_id] = account
        return account

    def get_account(self, account_id: str) -> Account:
        """Retrieve an account by its ID."""
        if account_id not in self.accounts:
            raise AccountNotFoundError(f"Account '{account_id}' not found.")
        return self.accounts[account_id]

    def get_balance(self, account_id: str) -> float:
        """Get the current balance of an account."""
        account = self.get_account(account_id)
        return account.balance

    def process_transaction(self, transaction: Transaction) -> Transaction:
        """Process a financial transaction and update account balances."""
        try:
            if transaction.transaction_type == TransactionType.DEPOSIT:
                transaction = self._process_deposit(transaction)
            elif transaction.transaction_type == TransactionType.WITHDRAWAL:
                transaction = self._process_withdrawal(transaction)
            elif transaction.transaction_type == TransactionType.TRANSFER:
                transaction = self._process_transfer(transaction)
            else:
                raise InvalidTransactionError(
                    f"Unknown transaction type: {transaction.transaction_type}"
                )
        except (InsufficientFundsError, AccountNotFoundError, InvalidTransactionError) as e:
            transaction.status = TransactionStatus.FAILED
            transaction.description += f" | Failed: {str(e)}"

        self.transactions[transaction.transaction_id] = transaction
        return transaction

    def _process_deposit(self, transaction: Transaction) -> Transaction:
        """Process a deposit transaction."""
        if not transaction.destination_account_id:
            raise InvalidTransactionError("Deposit requires a destination account.")

        dest_account = self.get_account(transaction.destination_account_id)
        dest_account.balance += transaction.amount
        dest_account.balance = round(dest_account.balance, 2)

        transaction.status = TransactionStatus.COMPLETED
        dest_account.transaction_history.append(transaction.transaction_id)
        return transaction

    def _process_withdrawal(self, transaction: Transaction) -> Transaction:
        """Process a withdrawal transaction."""
        if not transaction.source_account_id:
            raise InvalidTransactionError("Withdrawal requires a source account.")

        source_account = self.get_account(transaction.source_account_id)

        if source_account.balance < transaction.amount:
            raise InsufficientFundsError(
                f"Insufficient funds in account '{source_account.account_id}'. "
                f"Balance: {source_account.balance}, Requested: {transaction.amount}"
            )

        source_account.balance -= transaction.amount
        source_account.balance = round(source_account.balance, 2)

        transaction.status = TransactionStatus.COMPLETED
        source_account.transaction_history.append(transaction.transaction_id)
        return transaction

    def _process_transfer(self, transaction: Transaction) -> Transaction:
        """Process a transfer transaction between two accounts."""
        if not transaction.source_account_id or not transaction.destination_account_id:
            raise InvalidTransactionError(
                "Transfer requires both source and destination accounts."
            )

        if transaction.source_account_id == transaction.destination_account_id:
            raise InvalidTransactionError(
                "Source and destination accounts must be different."
            )

        source_account = self.get_account(transaction.source_account_id)
        dest_account = self.get_account(transaction.destination_account_id)

        if source_account.balance < transaction.amount:
            raise InsufficientFundsError(
                f"Insufficient funds in account '{source_account.account_id}'. "
                f"Balance: {source_account.balance}, Requested: {transaction.amount}"
            )

        source_account.balance -= transaction.amount
        source_account.balance = round(source_account.balance, 2)

        dest_account.balance += transaction.amount
        dest_account.balance = round(dest_account.balance, 2)

        transaction.status = TransactionStatus.COMPLETED
        source_account.transaction_history.append(transaction.transaction_id)
        dest_account.transaction_history.append(transaction.transaction_id)
        return transaction

    def reverse_transaction(self, transaction_id: str) -> Transaction:
        """Reverse a completed transaction."""
        if transaction_id not in self.transactions:
            raise InvalidTransactionError(f"Transaction '{transaction_id}' not found.")

        original = self.transactions[transaction_id]

        if original.status != TransactionStatus.COMPLETED:
            raise InvalidTransactionError(
                f"Cannot reverse transaction with status '{original.status.value}'."
            )

        reversal = Transaction(
            transaction_id=str(uuid.uuid4())[:8],
            transaction_type=original.transaction_type,
            amount=original.amount,
            source_account_id=original.destination_account_id,
            destination_account_id=original.source_account_id,
            timestamp=datetime.now(),
            description=f"Reversal of transaction {transaction_id}",
        )

        if original.transaction_type == TransactionType.DEPOSIT:
            reversal.transaction_type = TransactionType.WITHDRAWAL
            reversal.source_account_id = original.destination_account_id
            reversal.destination_account_id = None
        elif original.transaction_type == TransactionType.WITHDRAWAL:
            reversal.transaction_type = TransactionType.DEPOSIT
            reversal.destination_account_id = original.source_account_id
            reversal.source_account_id = None
        # For TRANSFER, the swap of source/destination is already done above

        result = self.process_transaction(reversal)

        if result.status == TransactionStatus.COMPLETED:
            original.status = TransactionStatus.REVERSED

        return result

    def create_and_process(
        self,
        transaction_type: TransactionType,
        amount: float,
        source_account_id: Optional[str] = None,
        destination_account_id: Optional[str] = None,
        description: str = "",
    ) -> Transaction:
        """Convenience method to create and process a transaction in one step."""
        transaction = Transaction(
            transaction_id=str(uuid.uuid4())[:8],
            transaction_type=transaction_type,
            amount=amount,
            source_account_id=source_account_id,
            destination_account_id=destination_account_id,
            timestamp=datetime.now(),
            description=description,
        )
        return self.process_transaction(transaction)

    def get_account_statement(self, account_id: str) -> list[dict]:
        """Get a list of all transactions for a given account."""
        account = self.get_account(account_id)
        statement = []
        for txn_id in account.transaction_history:
            txn = self.transactions.get(txn_id)
            if txn:
                statement.append(
                    {
                        "transaction_id": txn.transaction_id,
                        "type": txn.transaction_type.value,
                        "amount": txn.amount,
                        "status": txn.status.value,
                        "timestamp": txn.timestamp.isoformat(),
                        "description": txn.description,
                    }
                )
        return statement


def process_financial_transactions(transactions_data: list[dict]) -> dict:
    """
    Process a batch of financial transactions and return results.

    Each transaction dict should have:
        - type: "deposit", "withdrawal", or "transfer"
        - amount: float
        - source_account_id: str (for withdrawal/transfer)
        - destination_account_id: str (for deposit/transfer)

    Returns a summary dict with processed results.
    """
    processor = TransactionProcessor()
    results = {
        "processed": [],
        "failed": [],
        "total_processed": 0,
        "total_failed": 0,
        "accounts": {},
    }

    # Pre-create accounts mentioned in transactions if they don't exist
    account_ids = set()
    for txn_data in transactions_data:
        if txn_data.get("source_account_id"):
            account_ids.add(txn_data["source_account_id"])
        if txn_data.get("destination_account_id"):
            account_ids.add(txn_data["destination_account_id"])

    for acc_id in account_ids:
        account = Account(
            account_id=acc_id,
            owner_name=f"Owner-{acc_id}",
            balance=txn_data.get("initial_balance", 0.0),
        )
        processor.accounts[acc_id] = account

    # Override with explicit initial balances if provided
    for txn_data in transactions_data:
        if "initial_balances" in txn_data:
            for acc_id, balance in txn_data["initial_balances"].items():
                if acc_id in processor.accounts:
                    processor.accounts[acc_id].balance = balance

    for txn_data in transactions_data:
        try:
            txn_type = TransactionType(txn_data["type"])
            result = processor.create_and_process(
                transaction_type=txn_type,
                amount=txn_data["amount"],
                source_account_id=txn_data.get("source_account_id"),
                destination_account_id=txn_data.get("destination_account_id"),
                description=txn_data.get("description", ""),
            )

            entry = {
                "transaction_id": result.transaction_id,
                "type": result.transaction_type.value,
                "amount": result.amount,
                "status": result.status.value,
            }

            if result.status == TransactionStatus.COMPLETED:
                results["processed"].append(entry)
                results["total_processed"] += 1
            else:
                results["failed"].append(entry)
                results["total_failed"] += 1

        except (InvalidTransactionError, ValueError) as e:
            results["failed"].append(
                {
                    "error": str(e),
                    "data": txn_data,
                }
            )
            results["total_failed"] += 1

    # Collect final balances
    for acc_id, account in processor.accounts.items():
        results["accounts"][acc_id] = {
            "owner": account.owner_name,
            "balance": account.balance,
            "num_transactions": len(account.transaction_history),
        }

    return results


